let products = [];
try {
    const saved = localStorage.getItem('tsbd-products');
    if (saved) {
        products = JSON.parse(saved);
        // Automatically sync new hardcoded products to localStorage
        let updated = false;
        defaultProducts.forEach(dp => {
            if (!products.some(p => p.id === dp.id)) {
                products.push(dp);
                updated = true;
            }
        });
        if (updated) {
            localStorage.setItem('tsbd-products', JSON.stringify(products));
        }
    } else {
        products = [...defaultProducts];
    }
} catch (e) {
    products = [...defaultProducts];
}

