    const syncMobBadge = () => {
        const count = document.getElementById('cartCount');
        const mBadge = document.getElementById('mobCartBadge');
        if (!count || !mBadge) return;
        const c = parseInt(count.textContent) || 0;
        mBadge.textContent = c;
        mBadge.style.display = c > 0 ? 'flex' : 'none';
    };
    const cartCountEl = document.getElementById('cartCount');
    if (cartCountEl) new MutationObserver(syncMobBadge).observe(cartCountEl, { childList: true, characterData: true, subtree: true });

