    const sm = document.getElementById('sideMenu');
    if (sm) {
        sm.addEventListener('mouseenter', function () {
            this.style.width = '250px';
        });
        sm.addEventListener('mouseleave', function () {
            this.style.width = '60px';
        });

        const sideLinks = sm.querySelectorAll('a.side-menu__item');
        sideLinks.forEach(link => {
            link.addEventListener('click', (e) => {
                const path = window.location.pathname;
                if (path.endsWith('index.html') || path.endsWith('/')) {
                    e.preventDefault();

                    const url = new URL(link.href, window.location.origin);
                    const newFilter = url.searchParams.get('filter') || 'all';

                    const tabs = document.querySelectorAll('.filter-tab');
                    if (tabs.length) {
                        tabs.forEach(t => t.classList.remove('active'));
                        const activeTab = Array.from(tabs).find(t => t.dataset.filter === newFilter);
                        if (activeTab) activeTab.classList.add('active');
                    }

                    currentFilter = newFilter;
                    displayedProducts = 8;

                    window.history.pushState({}, '', link.href);

                    if (typeof renderProducts === 'function') {
                        renderProducts();
                    }

                    const productsSec = document.getElementById('products');
                    if (productsSec) {
                        productsSec.scrollIntoView({ behavior: 'smooth' });
                    }
                }
            });
        });
    }

