function addMultipleToCart(id, quantity) {
    const product = products.find(p => p.id === id);
    if (!product) return;

    const existing = cart.find(item => item.id === id);
    if (existing) {
        existing.qty += quantity;
    } else {
        cart.push({ ...product, qty: quantity });
    }

    updateCartUI();
    showToast(`${quantity}x ${product.name} added to cart!`);
}

function initCart() {
    const cartBtn = $('#cartBtn');
    const cartClose = $('#cartClose');
    const cartOverlay = $('#cartOverlay');
    const cartSidebar = $('#cartSidebar');

    if (cartBtn && cartSidebar && cartOverlay) {
        cartBtn.addEventListener('click', () => {
            cartSidebar.classList.add('active');
            cartOverlay.classList.add('active');
            document.body.style.overflow = 'hidden';
        });
    }

    const closeCart = () => {
        if (cartSidebar) cartSidebar.classList.remove('active');
        if (cartOverlay) cartOverlay.classList.remove('active');
        document.body.style.overflow = '';
    };

    if (cartClose) cartClose.addEventListener('click', closeCart);
    if (cartOverlay) cartOverlay.addEventListener('click', closeCart);
}

function addToCartById(id) {
    const product = products.find(p => p.id === id);
    if (!product) return;

    const existing = cart.find(item => item.id === id);
    if (existing) {
        existing.qty += 1;
    } else {
        cart.push({ ...product, qty: 1 });
    }

    updateCartUI();
    showToast(`${product.name} added to cart!`);
}

function removeFromCart(id) {
    cart = cart.filter(item => item.id !== id);
    updateCartUI();
}

function updateCartUI() {
    const cartCount = $('#cartCount');
    const cartItems = $('#cartItems');
    const cartFooter = $('#cartFooter');
    const cartTotal = $('#cartTotal');
    const cartTotalHeader = $('#cartTotalHeader');

    const totalItems = cart.reduce((sum, item) => sum + item.qty, 0);
    cartCount.textContent = totalItems;
    cartCount.style.display = totalItems > 0 ? 'flex' : 'none';

    if (cart.length === 0) {
        cartItems.innerHTML = `
            <div class="cart-empty">
                <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1" opacity="0.3"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>
                <p>Your cart is empty</p>
            </div>
        `;
        cartFooter.style.display = 'none';
        if (cartTotalHeader) cartTotalHeader.textContent = '৳0.00';
        return;
    }

    cartFooter.style.display = 'block';
    cartItems.innerHTML = cart.map(item => `
        <div class="cart-item">
            ${item.image ? `<img src="${item.image}" alt="${item.name}" style="width: 48px; height: 48px; object-fit: contain; flex-shrink: 0;">` : `
            <div class="cart-item__icon" style="background: ${item.gradient};">
                <span>${item.icon}</span>
            </div>
            `}
            <div class="cart-item__info">
                <div class="cart-item__name">${item.name}</div>
                <div style="display:flex; align-items:center; justify-content:space-between; margin-top: 4px;">
                    <div class="cart-item__price" style="margin:0;">৳${item.price.toLocaleString()}</div>
                    <div style="display:flex; align-items:center; background:var(--bg-glass); border:1px solid var(--border-color); border-radius:4px; overflow:hidden;">
                        <button onclick="updateCartQty(${item.id}, -1)" style="width:24px; height:24px; border:none; background:transparent; color:var(--text-primary); cursor:pointer; font-weight:bold;">-</button>
                        <span style="width:24px; text-align:center; font-size:0.85rem; font-weight:600;">${item.qty}</span>
                        <button onclick="updateCartQty(${item.id}, 1)" style="width:24px; height:24px; border:none; background:transparent; color:var(--text-primary); cursor:pointer; font-weight:bold;">+</button>
                    </div>
                </div>
            </div>
            <button class="cart-item__remove" onclick="removeFromCart(${item.id})" aria-label="Remove ${item.name}">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
            </button>
        </div>
    `).join('');

    const total = cart.reduce((sum, item) => sum + item.price * item.qty, 0);
    cartTotal.textContent = `৳${total.toLocaleString()}`;
    if (cartTotalHeader) cartTotalHeader.textContent = `৳${total.toLocaleString()}`;
}

function updateCartQty(id, delta) {
    const item = cart.find(i => i.id === id);
    if (!item) return;
    item.qty += delta;
    if (item.qty <= 0) {
        removeFromCart(id);
    } else {
        updateCartUI();
    }
}

function showToast(message) {
    const toast = $('#toast');
    const toastMessage = $('#toastMessage');
    toastMessage.textContent = message;
    toast.classList.add('active');
    setTimeout(() => toast.classList.remove('active'), 2500);
}

function initScrollAnimations() {
    const observerOptions = { threshold: 0.1, rootMargin: '0px 0px -50px 0px' };
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.style.opacity = '1';
                entry.target.style.transform = 'translateY(0)';
                observer.unobserve(entry.target);
            }
        });
    }, observerOptions);

    const animateElements = $$('.category-card, .feature-card, .testimonial-card, .section-header');
    animateElements.forEach(el => {
        el.style.opacity = '0';
        el.style.transform = 'translateY(30px)';
        el.style.transition = 'opacity 0.6s ease, transform 0.6s ease';
        observer.observe(el);
    });
}

function initCounterAnimation() {
    const counters = $$('.stat__number');
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const el = entry.target;
                const target = parseInt(el.dataset.count);
                animateCounter(el, target);
                observer.unobserve(el);
            }
        });
    }, { threshold: 0.5 });

    counters.forEach(counter => observer.observe(counter));
}

function animateCounter(el, target) {
    const duration = 2000;
    const start = performance.now();

    function update(now) {
        const elapsed = now - start;
        const progress = Math.min(elapsed / duration, 1);
        const ease = 1 - Math.pow(1 - progress, 3);
        el.textContent = Math.floor(target * ease).toLocaleString();
        if (progress < 1) requestAnimationFrame(update);
    }

    requestAnimationFrame(update);
}

function initFormHandlers() {
    const ctaForm = $('#ctaForm');
    if (ctaForm) {
        ctaForm.addEventListener('submit', (e) => {
            e.preventDefault();
            showToast('🎉 Subscribed! Check your email for 10% off code.');
            ctaForm.reset();
        });
    }

    const contactForm = $('#contactForm');
    if (contactForm) {
        contactForm.addEventListener('submit', (e) => {
            e.preventDefault();
            showToast('📩 Message sent! We\'ll reply within 24 hours.');
            contactForm.reset();
        });
    }

    const checkoutBtn = $('#checkoutBtn');
    if (checkoutBtn) {
        checkoutBtn.addEventListener('click', () => {
            if (cart.length === 0) return;
            const total = cart.reduce((sum, item) => sum + item.price * item.qty, 0);
            showToast(`📦 Order placed! Total: ৳${total.toLocaleString()}`);
            cart = [];
            updateCartUI();
            const sidebar = $('#cartSidebar');
            const overlay = $('#cartOverlay');
            if (sidebar) sidebar.classList.remove('active');
            if (overlay) overlay.classList.remove('active');
            document.body.style.overflow = '';
        });
    }
}

function initCategoryCards() {
    $$('.category-card').forEach(card => {
        card.addEventListener('click', () => {
            const category = card.dataset.category;
            if (!category) return;

            const path = window.location.pathname;
            if (path.endsWith('index.html') || path.endsWith('/')) {

                $$('.filter-tab').forEach(t => {
                    t.classList.remove('active');
                    if (t.dataset.filter === category) t.classList.add('active');
                });

                currentFilter = category;
                displayedProducts = 8;

                const url = new URL(window.location);
                url.searchParams.set('filter', currentFilter);
                window.history.pushState({}, '', url);

                if (typeof renderProducts === 'function') renderProducts();

                const productsSec = $('#products');
                if (productsSec) productsSec.scrollIntoView({ behavior: 'smooth' });
            } else {
                window.location.href = `index.html?filter=${category}`;
            }
        });
    });
}

